INSERT INTO t_p38294978_open_source_program_.egsu_legal_articles (document_id, article_number, title, content, tags) VALUES
  (2, 'Ст.46 УПК', 'Права подозреваемого', 'Подозреваемый вправе: знать, в чём подозревается; давать объяснения; пользоваться помощью защитника; представлять доказательства; заявлять ходатайства и отводы; давать показания на родном языке.', ARRAY['упк', 'подозреваемый', 'права', 'уголовный процесс']),
  (2, 'Ст.47 УПК', 'Права обвиняемого', 'Обвиняемый вправе: знать, в чём обвиняется; возражать против обвинения; давать показания либо отказаться; представлять доказательства; иметь защитника; знакомиться с материалами дела.', ARRAY['упк', 'обвиняемый', 'права', 'защита']),
  (2, 'Ст.51 УПК', 'Обязательное участие защитника', 'Участие защитника обязательно, если: лицо не отказалось от него; инкриминируется лишение свободы; лицо несовершеннолетнее; не может самостоятельно осуществлять защиту.', ARRAY['упк', 'защитник', 'адвокат']),
  (2, 'Ст.91 УПК', 'Основания задержания', 'Следователь вправе задержать подозреваемого: застигнутого при совершении преступления; когда очевидцы укажут на него; когда обнаружены следы преступления на нём или его вещах.', ARRAY['упк', 'задержание', 'основания']),
  (2, 'Ст.108 УПК', 'Заключение под стражу', 'Заключение под стражу применяется по судебному решению за преступление свыше 2 лет лишения свободы при невозможности применения более мягкой меры пресечения.', ARRAY['упк', 'арест', 'мера пресечения']),
  (2, 'Ст.125 УПК', 'Обжалование действий следователя в суд', 'Постановления следователя, способные нарушить конституционные права граждан или затруднить доступ к правосудию, могут быть обжалованы в суд по месту расследования.', ARRAY['упк', 'жалоба', 'обжалование', 'суд']),
  (2, 'Ст.144 УПК', 'Рассмотрение сообщений о преступлении', 'Следователь обязан принять и проверить любое сообщение о преступлении в срок не более 3 суток (до 30 суток при необходимости). По результатам — решение о возбуждении дела или отказе.', ARRAY['упк', 'заявление', 'сообщение о преступлении']),
  (2, 'Ст.148 УПК', 'Отказ в возбуждении дела', 'При отсутствии оснований следователь выносит постановление об отказе. Копия направляется заявителю. Постановление можно обжаловать прокурору или в суд.', ARRAY['упк', 'отказ', 'возбуждение дела']),
  (2, 'Ст.171 УПК', 'Предъявление обвинения', 'При наличии достаточных доказательств следователь выносит постановление о привлечении лица в качестве обвиняемого и предъявляет ему обвинение не позднее 3 суток с момента вынесения постановления.', ARRAY['упк', 'обвинение', 'следователь']),
  (2, 'Ст.389.2 УПК', 'Апелляционное обжалование', 'В апелляционном порядке обжалуются решения суда первой инстанции, не вступившие в силу. Право принесения апелляции — осуждённый, оправданный, защитник, потерпевший, прокурор.', ARRAY['упк', 'апелляция', 'обжалование']),
  (1, 'Ст.17 КРФ', 'Гарантия прав и свобод', 'В РФ признаются и гарантируются права и свободы человека согласно общепризнанным принципам международного права. Осуществление прав не должно нарушать права других лиц.', ARRAY['конституция', 'права', 'свободы']),
  (1, 'Ст.22 КРФ', 'Право на свободу', 'Каждый имеет право на свободу и личную неприкосновенность. Арест допускается только по судебному решению. Задержание без суда — не более 48 часов.', ARRAY['конституция', 'свобода', 'арест', '48 часов']),
  (1, 'Ст.29 КРФ', 'Свобода слова', 'Каждому гарантируется свобода мысли и слова. Никто не может быть принуждён к выражению мнений. Гарантируется свобода массовой информации. Цензура запрещается.', ARRAY['конституция', 'свобода слова', 'цензура']),
  (1, 'Ст.33 КРФ', 'Право на обращение', 'Граждане РФ вправе обращаться лично и направлять обращения в государственные органы, которые обязаны их рассмотреть в установленные сроки.', ARRAY['конституция', 'обращение', 'жалоба']),
  (1, 'Ст.53 КРФ', 'Возмещение вреда государством', 'Каждый имеет право на возмещение государством вреда, причинённого незаконными действиями или бездействием органов государственной власти или должностных лиц.', ARRAY['конституция', 'возмещение вреда', 'иск', 'государство']);
